// ─── Helpers ───────────────────────────────────────────────────────────────
function normalize(str) {
  if (!str) return '';
  return str.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim();
}
const STOP = ['ltda','eireli','epp','me','sa','ss','comercio','comercial','industria','servico','servicos','grupo','brasil','do','da','de','dos','das','e'];
function tokenize(str) {
  return normalize(str).split(' ').filter(t => t.length > 2 && !STOP.includes(t));
}

// ─── Dados de entrada ─────────────────────────────────────────────────────────
const normInput = $('Normalizar Nome').item.json;
const nomeNorm = normInput.nome_normalizado;
const tokens = normInput.tokens;

// ─── Merge + Dedup dos resultados ─────────────────────────────────────────────
// $input.all() agora tem TODOS os itens das duas buscas graças ao nó Merge
const seen = new Set();
const todos = [];
for (const item of $input.all()) {
  const clientes = item.json.data || [];
  for (const c of clientes) {
    if (!seen.has(c.id)) { seen.add(c.id); todos.push(c); }
  }
}

// ─── Score de semelhança ──────────────────────────────────────────────────────
function score(c) {
  const nC = normalize(c.nome||''), rC = normalize(c.razao_social||''), fC = normalize(c.nome_fantasia||'');
  if (nC === nomeNorm || rC === nomeNorm || fC === nomeNorm) return 100;
  let s = 0;
  if (nC.includes(nomeNorm) || nomeNorm.includes(nC)) s += 60;
  if (rC.includes(nomeNorm) || nomeNorm.includes(rC)) s += 55;
  if (fC.includes(nomeNorm) || nomeNorm.includes(fC)) s += 55;
  const tC = [...new Set([...tokenize(c.nome||''), ...tokenize(c.razao_social||''), ...tokenize(c.nome_fantasia||'')])];
  tokens.forEach(t => {
    if (tC.some(tc => tc.includes(t)||t.includes(tc))) s += 20;
    if (tC.includes(t)) s += 10;
  });
  if (tokens[0] && tC.some(tc => tc.includes(tokens[0]))) s += 15;
  return s;
}

// Ranquear TODOS — sem limite de top 5
const rankados = todos
  .map(c => ({...c, _score: score(c)}))
  .filter(c => c._score > 0)
  .sort((a,b) => b._score - a._score);

// ─── Not found ────────────────────────────────────────────────────────────────
if (rankados.length === 0) {
  return [{ json: {
    resultado: 'Nenhum cliente encontrado para "' + normInput.nome_original + '". Peça mais informações.',
    clientes: [], total_encontrado: 0, status: 'not_found'
  }}];
}

// ─── Helper endereço ──────────────────────────────────────────────────────────
const addr = c => {
  const e = c.enderecos && c.enderecos[0] && c.enderecos[0].endereco;
  return e ? (e.logradouro + ', ' + e.numero + ' - ' + e.bairro + ' - ' + e.nome_cidade + '/' + e.estado) : '';
};

// ─── Single match: score exato 100 OU único resultado com score ≥ 60 ──────────
if (rankados[0]._score === 100 || (rankados.length === 1 && rankados[0]._score >= 60)) {
  const c = rankados[0], end = addr(c);
  return [{ json: {
    resultado: 'Achei: *' + c.nome + '*' + (c.razao_social ? ' (' + c.razao_social + ')' : '') + (end ? ' — ' + end : '') + '. Confirma?',
    cliente_id: String(c.id),
    cliente_nome: c.nome,
    clientes: [{ id: c.id, nome: c.nome, razao_social: c.razao_social||'', telefone: c.telefone||c.celular||'', endereco: end }],
    total_encontrado: 1,
    status: 'single_match'
  }}];
}

// ─── Multiple matches: mostra TODOS os resultados ranqueados ──────────────────
const fmt = (c, i) => {
  const e = c.enderecos && c.enderecos[0] && c.enderecos[0].endereco;
  const cidade = e ? (e.nome_cidade + '/' + e.estado) : '';
  const tel = c.telefone || c.celular || '';
  return (i+1) + '. ' + c.nome + (cidade ? ' — ' + cidade : '') + (tel ? ' | ' + tel : '');
};
const option_map = {};
rankados.forEach((c,i) => { option_map[String(i+1)] = { id: String(c.id), nome: c.nome }; });

return [{ json: {
  resultado: 'Encontrei ' + rankados.length + ' clientes com nome parecido:\n' + rankados.map(fmt).join('\n') + '\n\nQual é o correto? Responde o número.',
  option_map: option_map,
  clientes: rankados.map(c => ({ id: c.id, nome: c.nome, razao_social: c.razao_social||'', telefone: c.telefone||c.celular||'', endereco: addr(c) })),
  total_encontrado: rankados.length,
  status: 'multiple_matches'
}}];
